from sqlalchemy import func, select
from sqlalchemy.orm import Session

from app.models.project import Project
from app.models.recording import Recording
from app.schemas.project import ProjectCreate, ProjectUpdate


def get_projects(db: Session) -> list[dict]:
    projects = db.execute(select(Project).order_by(Project.created_at.desc())).scalars().all()
    result = []
    for p in projects:
        count = db.execute(
            select(func.count()).where(Recording.project_id == p.id)
        ).scalar() or 0
        result.append({**p.__dict__, "recording_count": count})
    return result


def get_project(db: Session, project_id: int) -> Project | None:
    return db.get(Project, project_id)


def create_project(db: Session, data: ProjectCreate) -> Project:
    project = Project(name=data.name, description=data.description)
    db.add(project)
    db.commit()
    db.refresh(project)
    return project


def update_project(db: Session, project_id: int, data: ProjectUpdate) -> Project | None:
    project = db.get(Project, project_id)
    if not project:
        return None
    if data.name is not None:
        project.name = data.name
    if data.description is not None:
        project.description = data.description
    db.commit()
    db.refresh(project)
    return project


def delete_project(db: Session, project_id: int) -> bool:
    project = db.get(Project, project_id)
    if not project:
        return False
    db.delete(project)
    db.commit()
    return True

from fastapi import APIRouter, HTTPException
from sqlalchemy.orm import Session

from app.api.deps import DBSession
from app.schemas.project import ProjectCreate, ProjectResponse, ProjectUpdate
from app.services import project_service

router = APIRouter(prefix="/projects")


@router.get("", response_model=list[ProjectResponse])
def list_projects(db: Session = DBSession):
    return project_service.get_projects(db)


@router.post("", response_model=ProjectResponse, status_code=201)
def create_project(data: ProjectCreate, db: Session = DBSession):
    return project_service.create_project(db, data)


@router.get("/{project_id}", response_model=ProjectResponse)
def get_project(project_id: int, db: Session = DBSession):
    project = project_service.get_project(db, project_id)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    count_data = project_service.get_projects(db)
    for p in count_data:
        if p["id"] == project_id:
            return p
    return project


@router.put("/{project_id}", response_model=ProjectResponse)
def update_project(project_id: int, data: ProjectUpdate, db: Session = DBSession):
    project = project_service.update_project(db, project_id, data)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    return project


@router.delete("/{project_id}")
def delete_project(project_id: int, db: Session = DBSession):
    if not project_service.delete_project(db, project_id):
        raise HTTPException(status_code=404, detail="Project not found")
    return {"message": "Deleted"}

