/* ============================================
   SoundVault — Dark industrial recorder UI
   Font: Syne (display) + DM Mono (data)
   Theme: Dark charcoal + electric amber accent
   ============================================ */

*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --font-display: 'Syne', sans-serif;
  --font-mono: 'DM Mono', monospace;

  --bg: #0e0f11;
  --bg-surface: #16181c;
  --bg-elevated: #1d2026;
  --bg-hover: #252830;

  --accent: #f0b429;
  --accent-dim: rgba(240, 180, 41, 0.12);
  --accent-glow: rgba(240, 180, 41, 0.35);

  --text: #e8eaf0;
  --text-muted: #7a7f8e;
  --text-dim: #4a4f5c;

  --border: rgba(255,255,255,0.07);
  --border-accent: rgba(240, 180, 41, 0.4);

  --red: #ff4d4d;
  --red-dim: rgba(255, 77, 77, 0.12);
  --green: #4ade80;

  --sidebar-w: 260px;

  --radius-sm: 6px;
  --radius-md: 10px;
  --radius-lg: 16px;

  --ease: cubic-bezier(0.4, 0, 0.2, 1);
}

html, body {
  height: 100%;
  font-family: var(--font-display);
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
  overflow: hidden;
}

/* ============================================
   LAYOUT: sidebar + main
   ============================================ */

body {
  display: flex;
}

/* --- SIDEBAR --- */
.sidebar {
  width: var(--sidebar-w);
  min-width: var(--sidebar-w);
  height: 100vh;
  background: var(--bg-surface);
  border-right: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  transition: width 0.3s var(--ease), min-width 0.3s var(--ease), opacity 0.3s;
  overflow: hidden;
  position: relative;
  z-index: 10;
}

.sidebar.collapsed {
  width: 0;
  min-width: 0;
  opacity: 0;
}

.sidebar__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 16px 16px;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}

.sidebar__logo {
  display: flex;
  align-items: center;
  gap: 10px;
  white-space: nowrap;
}

.sidebar__logo-icon {
  font-size: 22px;
  color: var(--accent);
  line-height: 1;
}

.sidebar__logo-text {
  font-size: 17px;
  font-weight: 800;
  letter-spacing: -0.3px;
  color: var(--text);
}

.sidebar__toggle {
  background: none;
  border: 1px solid var(--border);
  color: var(--text-muted);
  width: 28px;
  height: 28px;
  border-radius: var(--radius-sm);
  cursor: pointer;
  font-size: 18px;
  line-height: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  transition: all 0.15s;
}

.sidebar__toggle:hover {
  background: var(--bg-hover);
  color: var(--text);
}

.sidebar__section {
  flex: 1;
  overflow-y: auto;
  padding: 12px 0;
}

.sidebar__section::-webkit-scrollbar { width: 4px; }
.sidebar__section::-webkit-scrollbar-track { background: transparent; }
.sidebar__section::-webkit-scrollbar-thumb { background: var(--border); border-radius: 4px; }

.sidebar__section-label {
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  color: var(--text-dim);
  padding: 4px 16px 8px;
}

.sidebar__footer {
  padding: 12px;
  border-top: 1px solid var(--border);
  flex-shrink: 0;
}

/* --- PROJECT LIST in sidebar --- */
.project-list {
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding: 0 8px;
}

.project-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 9px 10px;
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: background 0.15s;
  white-space: nowrap;
  overflow: hidden;
  position: relative;
  border: 1px solid transparent;
}

.project-item:hover { background: var(--bg-hover); }

.project-item.active {
  background: var(--accent-dim);
  border-color: var(--border-accent);
}

.project-item__icon {
  font-size: 14px;
  flex-shrink: 0;
  opacity: 0.6;
}

.project-item.active .project-item__icon { opacity: 1; }

.project-item__info {
  flex: 1;
  overflow: hidden;
}

.project-item__name {
  font-size: 13.5px;
  font-weight: 600;
  color: var(--text);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.project-item.active .project-item__name { color: var(--accent); }

.project-item__count {
  font-family: var(--font-mono);
  font-size: 10px;
  color: var(--text-dim);
  margin-top: 1px;
}

.project-item__del {
  opacity: 0;
  background: none;
  border: none;
  color: var(--text-dim);
  cursor: pointer;
  font-size: 14px;
  padding: 2px 4px;
  border-radius: 4px;
  transition: all 0.15s;
  flex-shrink: 0;
}

.project-item:hover .project-item__del { opacity: 1; }
.project-item__del:hover { color: var(--red); background: var(--red-dim); }

/* Skeleton */
.skeleton-list { padding: 4px 0; display: flex; flex-direction: column; gap: 6px; }
.skeleton-item {
  height: 38px;
  background: var(--bg-elevated);
  border-radius: var(--radius-sm);
  animation: pulse 1.5s ease-in-out infinite;
}
@keyframes pulse {
  0%, 100% { opacity: 0.5; }
  50% { opacity: 1; }
}

/* --- MAIN --- */
.main {
  flex: 1;
  display: flex;
  flex-direction: column;
  height: 100vh;
  overflow: hidden;
  min-width: 0;
}

/* --- TOPBAR --- */
.topbar {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 14px 24px;
  border-bottom: 1px solid var(--border);
  background: var(--bg-surface);
  flex-shrink: 0;
}

.topbar__menu-btn {
  background: none;
  border: 1px solid var(--border);
  color: var(--text-muted);
  width: 32px;
  height: 32px;
  border-radius: var(--radius-sm);
  cursor: pointer;
  font-size: 16px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.15s;
}

.topbar__menu-btn:hover { background: var(--bg-hover); color: var(--text); }

.topbar__breadcrumb {
  flex: 1;
  font-size: 13px;
