}

.btn--icon:hover { background: var(--bg-hover); color: var(--text); }

/* ============================================
   INPUTS
   ============================================ */

.input {
  width: 100%;
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  color: var(--text);
  font-family: var(--font-display);
  font-size: 14px;
  padding: 10px 14px;
