/* Skeleton */
.skeleton-list { padding: 4px 0; display: flex; flex-direction: column; gap: 6px; }
.skeleton-item {
  height: 38px;
  background: var(--bg-elevated);
  border-radius: var(--radius-sm);
  animation: pulse 1.5s ease-in-out infinite;
}
@keyframes pulse {
  0%, 100% { opacity: 0.5; }
  50% { opacity: 1; }
}

/* --- MAIN --- */
.main {
  flex: 1;
  display: flex;
  flex-direction: column;
  height: 100vh;
  overflow: hidden;
  min-width: 0;
}

/* --- TOPBAR --- */
.topbar {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 14px 24px;
  border-bottom: 1px solid var(--border);
  background: var(--bg-surface);
  flex-shrink: 0;
}

.topbar__menu-btn {
  background: none;
  border: 1px solid var(--border);
  color: var(--text-muted);
  width: 32px;
  height: 32px;
  border-radius: var(--radius-sm);
  cursor: pointer;
  font-size: 16px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.15s;
}

.topbar__menu-btn:hover { background: var(--bg-hover); color: var(--text); }

.topbar__breadcrumb {
  flex: 1;
  font-size: 13px;
  color: var(--text-muted);
  display: flex;
  align-items: center;
  gap: 8px;
}

.topbar__actions {
  display: flex;
  align-items: center;
  gap: 8px;
}

/* --- CONTENT AREA --- */
.content {
  flex: 1;
  overflow-y: auto;
  padding: 32px 36px;
}

.content::-webkit-scrollbar { width: 6px; }
.content::-webkit-scrollbar-track { background: transparent; }
.content::-webkit-scrollbar-thumb { background: var(--border); border-radius: 4px; }

/* ============================================
   WELCOME SCREEN
   ============================================ */

.welcome {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  min-height: 60vh;
  gap: 20px;
}

.welcome__visual {
  font-size: 72px;
  color: var(--accent);
  opacity: 0.3;
  line-height: 1;
  animation: float 4s ease-in-out infinite;
}

@keyframes float {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-10px); }
}

.welcome__title {
  font-size: 28px;
  font-weight: 800;
  letter-spacing: -0.5px;
}

.welcome__desc {
  color: var(--text-muted);
  max-width: 380px;
  line-height: 1.7;
}

/* ============================================
   PROJECT DETAIL
   ============================================ */

.project-detail {
  display: flex;
  flex-direction: column;
  gap: 28px;
  max-width: 720px;
  animation: fadeUp 0.3s var(--ease);
}

@keyframes fadeUp {
  from { opacity: 0; transform: translateY(12px); }
  to { opacity: 1; transform: translateY(0); }
}

.project-detail__header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 16px;
}

.project-detail__name {
  font-size: 26px;
  font-weight: 800;
  letter-spacing: -0.5px;
  color: var(--text);
}

.project-detail__desc {
  margin-top: 6px;
  color: var(--text-muted);
  font-size: 14px;
  line-height: 1.6;
}

/* ============================================
   RECORDER WIDGET
   ============================================ */

.recorder {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 24px;
  display: flex;
  flex-direction: column;
  gap: 20px;
  position: relative;
  overflow: hidden;
}

.recorder::before {
  content: '';
  position: absolute;
  inset: 0;
  background: radial-gradient(ellipse at 50% 0%, rgba(240,180,41,0.05) 0%, transparent 70%);
  pointer-events: none;
}

.recorder.recording {
  border-color: var(--border-accent);
  box-shadow: 0 0 0 1px var(--border-accent), 0 0 30px rgba(240, 180, 41, 0.08);
}

.recorder__top {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.recorder__status {
  display: flex;
  align-items: center;
  gap: 8px;
  font-family: var(--font-mono);
  font-size: 12px;
  color: var(--text-muted);
}

.recorder__dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--text-dim);
  transition: background 0.3s;
}

.recorder__dot.recording {
  background: var(--red);
  animation: blink 1s ease-in-out infinite;
}

@keyframes blink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.3; }
}

.recorder__timer {
  font-family: var(--font-mono);
  font-size: 32px;
  font-weight: 500;
  color: var(--text);
  letter-spacing: 3px;
}

/* Waveform bars */
.recorder__waveform {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 4px;
  height: 48px;
}

.recorder__waveform span {
  display: block;
  width: 4px;
  background: var(--text-dim);
  border-radius: 2px;
  height: 8px;
  transition: height 0.1s;
}

.recorder.recording .recorder__waveform span {
  background: var(--accent);
  animation: wave 0.8s ease-in-out infinite;
}

.recorder.recording .recorder__waveform span:nth-child(1)  { animation-delay: 0.00s; }
.recorder.recording .recorder__waveform span:nth-child(2)  { animation-delay: 0.08s; }
.recorder.recording .recorder__waveform span:nth-child(3)  { animation-delay: 0.16s; }
.recorder.recording .recorder__waveform span:nth-child(4)  { animation-delay: 0.24s; }
.recorder.recording .recorder__waveform span:nth-child(5)  { animation-delay: 0.32s; }
.recorder.recording .recorder__waveform span:nth-child(6)  { animation-delay: 0.40s; }
.recorder.recording .recorder__waveform span:nth-child(7)  { animation-delay: 0.48s; }
.recorder.recording .recorder__waveform span:nth-child(8)  { animation-delay: 0.56s; }
.recorder.recording .recorder__waveform span:nth-child(9)  { animation-delay: 0.64s; }
.recorder.recording .recorder__waveform span:nth-child(10) { animation-delay: 0.72s; }
.recorder.recording .recorder__waveform span:nth-child(11) { animation-delay: 0.56s; }
.recorder.recording .recorder__waveform span:nth-child(12) { animation-delay: 0.48s; }
.recorder.recording .recorder__waveform span:nth-child(13) { animation-delay: 0.32s; }
.recorder.recording .recorder__waveform span:nth-child(14) { animation-delay: 0.16s; }
.recorder.recording .recorder__waveform span:nth-child(15) { animation-delay: 0.00s; }

@keyframes wave {
  0%, 100% { height: 6px; }
  50% { height: 36px; }
}

.recorder__controls {
  display: flex;
  gap: 12px;
  justify-content: center;
}

.recorder__btn {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 12px 24px;
  border-radius: var(--radius-md);
  font-family: var(--font-display);
  font-size: 14px;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.2s var(--ease);
  border: none;
}

.recorder__btn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
}

.recorder__btn--record {
  background: var(--accent);
  color: #0e0f11;
}

.recorder__btn--record:not(:disabled):hover {
  background: #ffc93c;
  box-shadow: 0 0 20px var(--accent-glow);
  transform: translateY(-1px);
}

.recorder__btn--stop {
  background: var(--bg-elevated);
  color: var(--text);
  border: 1px solid var(--border);
}

.recorder__btn--stop:not(:disabled):hover {
  background: var(--red-dim);
  border-color: var(--red);
  color: var(--red);
}

/* Preview */
.recorder__preview {
  border-top: 1px solid var(--border);
  padding-top: 20px;
  display: flex;
  flex-direction: column;
  gap: 14px;
  animation: fadeUp 0.3s var(--ease);
}

.recorder__preview audio {
  width: 100%;
  border-radius: var(--radius-sm);
  accent-color: var(--accent);
}

.recorder__preview-form {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.recorder__preview-btns {
  display: flex;
  gap: 8px;
}

/* ============================================
   RECORDINGS LIST
   ============================================ */

.recordings-section {
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.recordings-section__header {
  display: flex;
  align-items: center;
  gap: 10px;
}

.recordings-section__title {
  font-size: 15px;
  font-weight: 700;
  color: var(--text);
}

.badge {
  background: var(--bg-elevated);
  color: var(--text-muted);
  font-family: var(--font-mono);
  font-size: 11px;
  padding: 2px 8px;
  border-radius: var(--radius-full);
  border: 1px solid var(--border);
}

.recordings-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.recording-card {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  transition: border-color 0.2s;
  animation: fadeUp 0.25s var(--ease);
}

.recording-card:hover { border-color: rgba(255,255,255,0.14); }

.recording-card__header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
}

.recording-card__name {
  font-size: 14px;
  font-weight: 700;
  color: var(--text);
  flex: 1;
}

.recording-card__meta {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-shrink: 0;
}

.recording-card__time {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-dim);
}

.recording-card__del {
  background: none;
  border: none;
  color: var(--text-dim);
  cursor: pointer;
  font-size: 14px;
  padding: 2px 6px;
  border-radius: 4px;
  transition: all 0.15s;
}

.recording-card__del:hover { color: var(--red); background: var(--red-dim); }

.recording-card audio {
  width: 100%;
  height: 36px;
  accent-color: var(--accent);
}

.recording-card__info {
  display: flex;
  gap: 14px;
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-dim);
}

/* ============================================
   BUTTONS
   ============================================ */

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 9px 18px;
  border-radius: var(--radius-md);
  font-family: var(--font-display);
  font-size: 13.5px;
  font-weight: 700;
  cursor: pointer;
  border: none;
  transition: all 0.2s var(--ease);
  white-space: nowrap;
}

.btn:disabled { opacity: 0.4; cursor: not-allowed; }

.btn--primary {
  background: var(--accent);
  color: #0e0f11;
}

.btn--primary:not(:disabled):hover {
  background: #ffc93c;
  box-shadow: 0 0 16px var(--accent-glow);
}

.btn--ghost {
  background: var(--bg-elevated);
  color: var(--text-muted);
  border: 1px solid var(--border);
}

.btn--ghost:hover { background: var(--bg-hover); color: var(--text); }

.btn--danger {
  background: var(--red-dim);
  color: var(--red);
  border: 1px solid rgba(255, 77, 77, 0.3);
}

.btn--danger:hover { background: rgba(255,77,77,0.2); }

.btn--create {
  width: 100%;
  background: var(--bg-elevated);
  color: var(--text-muted);
  border: 1px dashed var(--border);
  padding: 10px;
  font-size: 13px;
  font-weight: 600;
  border-radius: var(--radius-md);
  gap: 6px;
}

.btn--create:hover {
  background: var(--accent-dim);
  border-color: var(--border-accent);
  color: var(--accent);
}

.btn--lg { padding: 13px 28px; font-size: 15px; }

.btn--icon {
  background: none;
  border: 1px solid var(--border);
  color: var(--text-muted);
  padding: 7px 10px;
  border-radius: var(--radius-sm);
  font-size: 13px;
}

.btn--icon:hover { background: var(--bg-hover); color: var(--text); }

/* ============================================
   INPUTS
   ============================================ */

.input {
  width: 100%;
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  color: var(--text);
  font-family: var(--font-display);
  font-size: 14px;
  padding: 10px 14px;
  outline: none;
  transition: border-color 0.2s;
}

.input:focus { border-color: var(--accent); }
.input::placeholder { color: var(--text-dim); }

.input--textarea {
  resize: vertical;
  min-height: 80px;
}

/* ============================================
   FIELDS
   ============================================ */

.field {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.field__label {
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.5px;
  color: var(--text-muted);
  text-transform: uppercase;
}

.field__error {
  font-size: 12px;
  color: var(--red);
  min-height: 16px;
}

.required { color: var(--red); }

/* ============================================
   MODAL
   ============================================ */

.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.7);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
  animation: fadeIn 0.2s;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

.modal {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  width: 100%;
  max-width: 460px;
  margin: 16px;
  animation: slideUp 0.25s var(--ease);
}

@keyframes slideUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}

.modal--sm { max-width: 360px; }

.modal__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 20px 0;
}

.modal__title {
  font-size: 17px;
  font-weight: 800;
}

.modal__close {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 16px;
  padding: 4px;
  transition: color 0.15s;
}

.modal__close:hover { color: var(--text); }

.modal__body {
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.modal__body p { color: var(--text-muted); font-size: 14px; line-height: 1.6; }

.modal__footer {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
  padding-top: 8px;
  border-top: 1px solid var(--border);
}

/* ============================================
   EMPTY STATE
   ============================================ */

.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
  padding: 36px 20px;
  color: var(--text-dim);
  font-size: 14px;
  text-align: center;
  border: 1px dashed var(--border);
  border-radius: var(--radius-lg);
}

.empty-state__icon { font-size: 36px; opacity: 0.5; }
.empty-state strong { color: var(--accent); }

/* ============================================
   TOAST NOTIFICATIONS
   ============================================ */

.toast-container {
  position: fixed;
  bottom: 24px;
  right: 24px;
  display: flex;
  flex-direction: column;
  gap: 8px;
  z-index: 200;
}

.toast {
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  color: var(--text);
  padding: 12px 18px;
  border-radius: var(--radius-md);
  font-size: 13.5px;
  font-weight: 600;
  box-shadow: 0 8px 24px rgba(0,0,0,0.4);
  animation: toastIn 0.3s var(--ease);
  max-width: 320px;
}

.toast--success { border-color: rgba(74, 222, 128, 0.4); color: var(--green); }
.toast--error { border-color: rgba(255, 77, 77, 0.4); color: var(--red); }

@keyframes toastIn {
  from { opacity: 0; transform: translateX(20px); }
  to { opacity: 1; transform: translateX(0); }
}

@keyframes toastOut {
  from { opacity: 1; transform: translateX(0); }
  to { opacity: 0; transform: translateX(20px); }
}

/* ============================================
   SPINNER
   ============================================ */

.spinner {
  width: 18px;
  height: 18px;
  border: 2px solid rgba(255,255,255,0.2);
  border-top-color: var(--accent);
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
  display: inline-block;
}

@keyframes spin { to { transform: rotate(360deg); } }

/* ============================================
   MISC
   ============================================ */

:root { --radius-full: 999px; }

/* ============================================
   RESPONSIVE
   ============================================ */

@media (max-width: 640px) {
  :root { --sidebar-w: 240px; }

  .content { padding: 20px 16px; }

  .recorder__timer { font-size: 24px; }

  .recorder__btn { padding: 10px 18px; font-size: 13px; }
}
