/**
 * SoundVault — Main Application
 * Project management + Audio recording with S3 upload
 */

// ============================================================
// STATE
// ============================================================
let projects = [];
let currentProjectId = null;
let mediaRecorder = null;
let audioChunks = [];
let recordingBlob = null;
let recordingDuration = 0;
let timerInterval = null;
let timerStart = null;

// ============================================================
// INIT
// ============================================================
document.addEventListener('DOMContentLoaded', () => {
  setupSidebar();
  setupModal();
  setupDeleteModal();
  setupRecorder();
  loadProjects();
});

// ============================================================
// UTILS
// ============================================================
function escapeHtml(text) {
  const div = document.createElement('div');
  div.textContent = text ?? '';
  return div.innerHTML;
}

function formatDate(iso) {
  return new Date(iso).toLocaleDateString('vi-VN', {
    day: '2-digit', month: '2-digit', year: 'numeric',
    hour: '2-digit', minute: '2-digit',
  });
}

function formatDuration(seconds) {
  if (!seconds) return '—';
  const m = Math.floor(seconds / 60);
  const s = Math.floor(seconds % 60);
  return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}

function formatBytes(bytes) {
  if (!bytes) return '—';
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

function showToast(message, type = 'success') {
  const container = document.getElementById('toastContainer');
  const toast = document.createElement('div');
  toast.className = `toast toast--${type}`;
  toast.textContent = message;
  container.appendChild(toast);
  setTimeout(() => {
    toast.style.animation = 'toastOut 0.3s ease forwards';
    setTimeout(() => toast.remove(), 300);
  }, 3500);
}

// ============================================================
// SIDEBAR
// ============================================================
function setupSidebar() {
  const sidebar = document.getElementById('sidebar');
  const toggleBtn = document.getElementById('sidebarToggle');
  const openBtn = document.getElementById('sidebarOpenBtn');

  toggleBtn.addEventListener('click', () => {
    sidebar.classList.add('collapsed');
    openBtn.style.display = 'flex';
  });

  openBtn.addEventListener('click', () => {
    sidebar.classList.remove('collapsed');
    openBtn.style.display = 'none';
  });

  document.getElementById('openCreateProject').addEventListener('click', openCreateModal);
  document.getElementById('welcomeCreateBtn').addEventListener('click', openCreateModal);
}

// ============================================================
// PROJECTS
// ============================================================
async function loadProjects() {
  try {
    projects = await api.get('/api/projects');
    renderProjectList();
    if (currentProjectId) {
      const exists = projects.find(p => p.id === currentProjectId);
      if (exists) openProject(currentProjectId);
      else showWelcome();
    } else {
      showWelcome();
    }
  } catch (err) {
    showToast('Không thể tải danh sách project: ' + err.message, 'error');
  }
}

function renderProjectList() {
  const list = document.getElementById('projectList');
  if (!projects.length) {
    list.innerHTML = `<div style="padding:8px 10px;font-size:12px;color:var(--text-dim)">Chưa có project nào.</div>`;
    return;
  }
  list.innerHTML = projects.map(p => `
    <div class="project-item ${p.id === currentProjectId ? 'active' : ''}" data-id="${p.id}" onclick="openProject(${p.id})">
      <span class="project-item__icon">📁</span>
      <div class="project-item__info">
        <div class="project-item__name">${escapeHtml(p.name)}</div>
        <div class="project-item__count">${p.recording_count} bản ghi</div>
      </div>
      <button class="project-item__del" title="Xoá project" onclick="event.stopPropagation(); confirmDeleteProject(${p.id}, '${escapeHtml(p.name)}')">✕</button>
    </div>
  `).join('');
}

function showWelcome() {
  currentProjectId = null;
  document.getElementById('welcomeScreen').style.display = 'flex';
  document.getElementById('projectDetail').style.display = 'none';
  document.getElementById('topbarBreadcrumb').innerHTML = `<span>SoundVault</span>`;
  document.getElementById('topbarActions').innerHTML = '';
  renderProjectList();
}

async function openProject(projectId) {
  currentProjectId = projectId;
  const project = projects.find(p => p.id === projectId);
  if (!project) return;

  document.getElementById('welcomeScreen').style.display = 'none';
  document.getElementById('projectDetail').style.display = 'flex';

  document.getElementById('detailProjectName').textContent = project.name;
  document.getElementById('detailProjectDesc').textContent = project.description || '';

  document.getElementById('topbarBreadcrumb').innerHTML = `
    <span style="color:var(--text-dim)">Projects</span>
    <span style="color:var(--text-dim)">›</span>
    <span>${escapeHtml(project.name)}</span>
  `;

  document.getElementById('topbarActions').innerHTML = `
    <button class="btn btn--icon" onclick="openEditModal(${project.id})" title="Sửa project">✎ Sửa</button>
  `;

  renderProjectList();
  resetRecorder();
  await loadRecordings(projectId);
}

// ============================================================
// CREATE / EDIT PROJECT MODAL
// ============================================================
let editingProjectId = null;

function openCreateModal() {
  editingProjectId = null;
  document.getElementById('modalTitle').textContent = 'Tạo project mới';
  document.getElementById('modalSubmit').textContent = 'Tạo';
  document.getElementById('projectName').value = '';
  document.getElementById('projectDesc').value = '';
  document.getElementById('projectNameError').textContent = '';
  document.getElementById('modalOverlay').style.display = 'flex';
  setTimeout(() => document.getElementById('projectName').focus(), 50);
}

function openEditModal(projectId) {
  const project = projects.find(p => p.id === projectId);
  if (!project) return;
  editingProjectId = projectId;
  document.getElementById('modalTitle').textContent = 'Sửa project';
  document.getElementById('modalSubmit').textContent = 'Lưu';
  document.getElementById('projectName').value = project.name;
  document.getElementById('projectDesc').value = project.description || '';
  document.getElementById('projectNameError').textContent = '';
  document.getElementById('modalOverlay').style.display = 'flex';
  setTimeout(() => document.getElementById('projectName').focus(), 50);
}

function closeModal() {
  document.getElementById('modalOverlay').style.display = 'none';
}

function setupModal() {
  document.getElementById('modalClose').addEventListener('click', closeModal);
  document.getElementById('modalCancel').addEventListener('click', closeModal);
  document.getElementById('modalOverlay').addEventListener('click', (e) => {
    if (e.target === e.currentTarget) closeModal();
  });

