}

function resetRecorder() {
  if (mediaRecorder && mediaRecorder.state !== 'inactive') {
    mediaRecorder.stop();
  }
  if (timerInterval) clearInterval(timerInterval);

  mediaRecorder = null;
  audioChunks = [];
  recordingBlob = null;
  recordingDuration = 0;

  const widget = document.getElementById('recorderWidget');
  widget.classList.remove('recording');

  document.getElementById('recorderDot').className = 'recorder__dot';
  document.getElementById('recorderStatusText').textContent = 'Sẵn sàng';
  document.getElementById('recorderTimer').textContent = '00:00';
  document.getElementById('btnRecord').disabled = false;
  document.getElementById('btnStop').disabled = true;

  document.getElementById('recorderPreview').style.display = 'none';
  document.getElementById('previewAudio').src = '';
