      document.getElementById('recordingNameInput').value = defaultName;
      document.getElementById('recorderPreview').style.display = 'flex';
    });

    mediaRecorder.start(100);
    timerStart = Date.now();
    timerInterval = setInterval(updateTimer, 500);

    document.getElementById('recorderWidget').classList.add('recording');
    document.getElementById('recorderDot').className = 'recorder__dot recording';
    document.getElementById('recorderStatusText').textContent = 'Đang ghi âm...';
