      const defaultName = `Ghi âm ${now.toLocaleDateString('vi-VN')} ${now.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' })}`;
      document.getElementById('recordingNameInput').value = defaultName;
      document.getElementById('recorderPreview').style.display = 'flex';
    });

    mediaRecorder.start(100);
    timerStart = Date.now();
    timerInterval = setInterval(updateTimer, 500);

    document.getElementById('recorderWidget').classList.add('recording');
    document.getElementById('recorderDot').className = 'recorder__dot recording';
    document.getElementById('recorderStatusText').textContent = 'Đang ghi âm...';
    document.getElementById('btnRecord').disabled = true;
    document.getElementById('btnStop').disabled = false;
    document.getElementById('recorderPreview').style.display = 'none';

  } catch (err) {
    showToast('Không thể truy cập microphone: ' + err.message, 'error');
  }
}

function updateTimer() {
  const elapsed = Math.floor((Date.now() - timerStart) / 1000);
  recordingDuration = elapsed;
  const m = Math.floor(elapsed / 60);
  const s = elapsed % 60;
  document.getElementById('recorderTimer').textContent =
    `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}

function stopRecording() {
  if (mediaRecorder && mediaRecorder.state !== 'inactive') {
    mediaRecorder.stop();
  }
  if (timerInterval) clearInterval(timerInterval);

  document.getElementById('recorderWidget').classList.remove('recording');
  document.getElementById('recorderDot').className = 'recorder__dot';
  document.getElementById('recorderStatusText').textContent = 'Hoàn thành';
  document.getElementById('btnRecord').disabled = false;
  document.getElementById('btnStop').disabled = true;
}

async function saveRecording() {
  if (!recordingBlob) return;

  const name = document.getElementById('recordingNameInput').value.trim();
  if (!name) {
    showToast('Vui lòng đặt tên cho bản ghi âm.', 'error');
    document.getElementById('recordingNameInput').focus();
    return;
  }

  const btn = document.getElementById('btnSaveRecording');
  const btnText = document.getElementById('btnSaveText');
  btn.disabled = true;
  btnText.innerHTML = '<span class="spinner" style="width:14px;height:14px;border-width:2px"></span> Đang lưu...';

  try {
    // Get extension from mime type
    const mime = recordingBlob.type || 'audio/webm';
    const ext = mime.includes('ogg') ? 'ogg' : mime.includes('mp4') ? 'mp4' : 'webm';
    const filename = `${name.replace(/[^a-zA-Z0-9_-]/g, '_')}.${ext}`;

    // Get presigned URL from S3
    const { upload_url, file_url } = await api.post('/api/upload/presigned-url', { filename });

    // Upload raw blob to S3
    const uploadRes = await fetch(upload_url, {
      method: 'PUT',
      body: recordingBlob,
      headers: { 'Content-Type': mime },
    });

    if (!uploadRes.ok) throw new Error(`Upload S3 thất bại: ${uploadRes.status}`);

    // Save metadata to DB
    await api.post('/api/recordings', {
      project_id: currentProjectId,
      name,
      audio_url: file_url,
      duration_seconds: recordingDuration,
      file_size_bytes: recordingBlob.size,
    });

    showToast('Đã lưu bản ghi âm!');
    resetRecorder();
    await loadRecordings(currentProjectId);
    await loadProjects(); // update count in sidebar

  } catch (err) {
    showToast('Lỗi khi lưu: ' + err.message, 'error');
  } finally {
    btn.disabled = false;
    btnText.textContent = 'Lưu bản ghi';
  }
}
